// GET /api/posts?limit=20&after=<cursor>

const MAX_LIMIT = 100;

// --- Cursor helpers --------------------------------------------------------

// Encode the (created_at, id) pair of the last row into an opaque token.
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode an opaque token back into { created_at, id }.
// Throws on anything malformed so the caller can return a 400.
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('Invalid cursor: not valid base64-encoded JSON');
    }

    if (
        parsed === null ||
        typeof parsed !== 'object' ||
        typeof parsed.id === 'undefined' ||
        typeof parsed.created_at === 'undefined'
    ) {
        throw new Error('Invalid cursor: missing required fields');
    }

    // Validate the timestamp is parseable.
    if (Number.isNaN(new Date(parsed.created_at).getTime())) {
        throw new Error('Invalid cursor: bad created_at');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ---------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range.
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > MAX_LIMIT) limit = MAX_LIMIT;

    // Build the query. We fetch limit + 1 rows (the N+1 trick) to detect
    // whether another page exists without a COUNT.
    let sql;
    let params;

    if (typeof req.query.after === 'string' && req.query.after.length > 0) {
        let cursor;
        try {
            cursor = decodeCursor(req.query.after);
        } catch (err) {
            return res.status(400).json({ error: err.message });
        }

        // Compound keyset condition matching ORDER BY created_at DESC, id DESC.
        // Row tuples ((a, b) < (x, y)) gives the correct lexicographic
        // comparison for the "next page" in descending order.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page — no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // If we got limit + 1 rows, there is at least one more page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Notes on the implementation

- **Keyset condition.** `(created_at, id) < ($1, $2)` is a PostgreSQL row-value comparison that maps exactly to `ORDER BY created_at DESC, id DESC`. It compares the tuples lexicographically, so it correctly handles rows that share the same `created_at` by falling through to `id` — no rows skipped or duplicated at page boundaries. For best performance, back it with a composite index: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;`
- **N+1 trick.** We request `limit + 1` rows. If that many come back, we know more pages exist, slice off the extra row, and build the cursor from the last *returned* row.
- **Opaque cursor.** The client only ever sees a base64url string. Encoding the sort key as JSON means you can evolve the cursor's contents later without changing the API contract. (`base64url` avoids `+`/`/`/`=` needing URL-escaping; plain `base64` works too if you prefer.)
- **Graceful failure.** `decodeCursor` throws on bad base64, bad JSON, or missing/invalid fields, and the handler turns that into a `400`.

## Why cursor-based is superior here

1. **Stable results under writes.** With `OFFSET`, inserting or deleting a post shifts every subsequent row, so a user paging through can see duplicates or skip items. A keyset cursor anchors to actual column values, so concurrent inserts/deletes don't corrupt pagination.
2. **Constant-time deep pages.** `OFFSET 100000` forces Postgres to scan and discard 100k rows on every request — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` seeks directly into the index and reads only the rows it returns, so page 5,000 costs the same as page 1.
3. **No expensive COUNT.** `COUNT(*)` on a large table scans a lot of rows just to compute `totalPages`. Dropping it (in favor of `hasMore`) removes a per-request full/index scan — exactly the trade-off your requirements call for.

The main thing you give up is random access ("jump to page 47") and a total count — both rarely needed for infinite-scroll / feed-style endpoints like a posts list.

