function encodeCursor(post) {
    const payload = {
        created_at: post.created_at instanceof Date
            ? post.created_at.toISOString()
            : post.created_at,
        id: post.id,
    };
    return Buffer.from(JSON.stringify(payload)).toString('base64url');
