/**
 * Decodes and validates a cursor string.
 * @param {string} cursor - The raw cursor value from the query string.
 * @returns {{ created_at: string, id: number } | null} Parsed cursor, or null if invalid.
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        if (
            typeof parsed !== 'object'                     ||
            parsed === null                                ||
            typeof parsed.created_at !== 'string'         ||
            isNaN(Date.parse(parsed.created_at))          ||  // must be a valid timestamp
            !Number.isInteger(parsed.id)                  ||  // must be an integer ID
            parsed.id <= 0
        ) {
            return null;
        }

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        return null;
    }
}
